    let mut routes: Vec<Route> = vec![
        Route::new_host("api.example.com", "api_origin", backend_api_origin()?),
        Route::new_host("static.example.com", "static_origin", backend_static_origin()?),
        Route::new_path_prefix("/internal/", "internal_origin", backend_internal_origin()?),
    ];

    routes.sort_by_key(|r| r.priority);

    for r in routes.drain(..) {
        if r.matches(&host, &path) {
            return Ok((r.name.to_string(), r.backend));
        }
    }

    Ok(("default_origin".to_string(), backend_default_origin()?))
