struct BackendParams<'a> {
    name: &'a str,
    host: &'a str,
    port: u16,
    sni_hostname: Option<&'a str>,
    use_tls: bool,
    allow_invalid_certs: bool,
    ca_cert_pem: Option<&'a [u8]>,
    client_cert: Option<ClientCertParams<'a>>,
    connect_timeout_ms: u32,
    first_byte_timeout_ms: u32,
    between_bytes_timeout_ms: u32,
    http_keepalive: bool,
}

struct ClientCertParams<'a> {
    cert_pem: &'a [u8],
    key_pem: &'a [u8],
}

fn build_backend(p: BackendParams<'_>) -> Result<Backend, Error> {
    let mut tls = if p.use_tls {
        let mut t = TlsConfig::new();
        if let Some(sni) = p.sni_hostname {
            t = t.sni_hostname(sni);
        }
        if p.allow_invalid_certs {
            t = t.allow_invalid_certificates(true);
        }
        if let Some(ca) = p.ca_cert_pem {
            t = t.ca_certificates(ca);
        }
        if let Some(cc) = p.client_cert {
            let client = ClientCertificate::new(cc.cert_pem, cc.key_pem)?;
            t = t.client_certificate(client);
        }
        Some(t)
    } else {
        None
    };

    let mut config = BackendConfig::new();
    config = config
        .connect_timeout(std::time::Duration::from_millis(p.connect_timeout_ms as u64))
        .first_byte_timeout(std::time::Duration::from_millis(p.first_byte_timeout_ms as u64))
        .between_bytes_timeout(std::time::Duration::from_millis(p.between_bytes_timeout_ms as u64));

    if let Some(tls_cfg) = tls.take() {
        config = config.tls_config(tls_cfg);
    }

    if p.http_keepalive {
        config = config.enable_http_keepalive();
    }

    let health = HealthCheck::new()
        .path("/health")
        .method(Method::GET)
        .expected_response(StatusCode::OK)
        .initial(1)
        .threshold(1)
        .timeout(std::time::Duration::from_millis(500));

    config = config.health_check(health);

    let b = BackendBuilder::new(p.name, p.host)
        .port(p.port)
        .backend_config(config)
        .finish()?;

    Ok(b)
}

